class TOTPSecret:
    """Represents a TOTP secret with associated metadata."""
    
    def __init__(self, secret: bytes, issuer: str, account_name: str,
                 digits: int = 6, period: int = 30, algorithm: str = "SHA1"):
        if len(secret) < 20:
            raise ValueError("Secret must be at least 20 bytes (160 bits) for adequate security")
        if digits not in (6, 8):
            raise ValueError("Digits must be 6 or 8")
        if period not in (30, 60):
            raise ValueError("Period must be 30 or 60 seconds")
        if algorithm not in ("SHA1", "SHA256", "SHA512"):
            raise ValueError("Algorithm must be SHA1, SHA256, or SHA512")
        
        self.secret = secret
        self.issuer = issuer
        self.account_name = account_name
        self.digits = digits
        self.period = period
        self.algorithm = algorithm
    
    @property
    def base32_secret(self) -> str:
        """Return the secret encoded in base32 (no padding)."""
        return base64.b32encode(self.secret).decode('ascii').rstrip('=')
    
    def get_otpauth_uri(self) -> str:
        """Generate the otpauth:// URI for QR code generation."""
        label = f"{quote(self.issuer)}:{quote(self.account_name)}"
        params = {
            "secret": self.base32_secret,
            "issuer": self.issuer,
            "algorithm": self.algorithm,
            "digits": str(self.digits),
            "period": str(self.period),
        }
        param_str = "&".join(f"{k}={quote(str(v))}" for k, v in params.items())
        return f"otpauth://totp/{label}?{param_str}"
    
    def to_dict(self) -> dict:
        """Serialize to dictionary (for storage). Secret is base32 encoded."""
        return {
            "secret_b32": self.base32_secret,
            "issuer": self.issuer,
            "account_name": self.account_name,
            "digits": self.digits,
            "period": self.period,
            "algorithm": self.algorithm,
        }
    
    @classmethod
    def from_dict(cls, data: dict) -> "TOTPSecret":
        """Deserialize from dictionary."""
        b32 = data["secret_b32"]
        # Add padding if needed
        padding = (8 - len(b32) % 8) % 8
        secret = base64.b32decode(b32 + "=" * padding)
        return cls(
            secret=secret,
            issuer=data["issuer"],
            account_name=data["account_name"],
            digits=data.get("digits", 6),
            period=data.get("period", 30),
            algorithm=data.get("algorithm", "SHA1"),
        )


class TOTPGenerator:
    """Generates and validates TOTP codes with protection against weak validation."""
    
    HASH_ALGORITHMS = {
        "SHA1": hashlib.sha1,
        "SHA256": hashlib.sha256,
        "SHA512": hashlib.sha512,
    }
    
    # Minimum secret length in bytes (160 bits as per RFC 4226)
    MIN_SECRET_LENGTH = 20
    
    # Maximum allowed time window for validation (to prevent overly permissive windows)
    MAX_ALLOWED_WINDOW = 1
    
    def __init__(self):
        # Track recently used codes to prevent replay attacks
        # Key: (user_id, code), Value: timestamp when used
        self._used_codes: dict[tuple[str, str], float] = {}
        self._used_codes_cleanup_interval = 300  # 5 minutes
        self._last_cleanup = time.time()
    
    def generate_secret(self, issuer: str, account_name: str,
                        secret_length: int = 32, digits: int = 6,
                        period: int = 30, algorithm: str = "SHA1") -> TOTPSecret:
        """
        Generate a new TOTP secret for a user.
        
        Args:
            issuer: The service/application name
            account_name: The user's account identifier (e.g., email)
            secret_length: Length of the secret in bytes (minimum 20)
            digits: Number of digits in the OTP (6 or 8)
            period: Time step in seconds (30 or 60)
            algorithm: Hash algorithm (SHA1, SHA256, SHA512)
        
        Returns:
            TOTPSecret object
        """
        if secret_length < self.MIN_SECRET_LENGTH:
            raise ValueError(
                f"Secret length must be at least {self.MIN_SECRET_LENGTH} bytes"
            )
        
        if not issuer or not issuer.strip():
            raise ValueError("Issuer must not be empty")
        if not account_name or not account_name.strip():
            raise ValueError("Account name must not be empty")
        
        # Generate cryptographically secure random bytes
        secret = os.urandom(secret_length)
        
        return TOTPSecret(
            secret=secret,
            issuer=issuer.strip(),
            account_name=account_name.strip(),
            digits=digits,
            period=period,
            algorithm=algorithm,
        )
    
    def _hotp(self, secret: bytes, counter: int, digits: int = 6,
              algorithm: str = "SHA1") -> str:
        """
        Generate an HOTP value as per RFC 4226.
        
        Args:
            secret: The shared secret
            counter: The counter value
            digits: Number of digits
            algorithm: Hash algorithm name
        
        Returns:
            OTP string with leading zeros preserved
        """
        hash_func = self.HASH_ALGORITHMS.get(algorithm)
        if hash_func is None:
            raise ValueError(f"Unsupported algorithm: {algorithm}")
        
        # Pack counter as 8-byte big-endian
        counter_bytes = struct.pack(">Q", counter)
        
        # Compute HMAC
        hmac_digest = hmac.new(secret, counter_bytes, hash_func).digest()
        
        # Dynamic truncation
        offset = hmac_digest[-1] & 0x0F
        truncated = struct.unpack(">I", hmac_digest[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF
        
        # Generate OTP with proper zero-padding
        otp = truncated % (10 ** digits)
        return str(otp).zfill(digits)
    
    def generate_totp(self, totp_secret: TOTPSecret,
                      timestamp: float | None = None) -> str:
        """
        Generate a TOTP code for the given secret and time.
        
        Args:
            totp_secret: The TOTPSecret object
            timestamp: Unix timestamp (defaults to current time)
        
        Returns:
            TOTP code string
        """
        if timestamp is None:
            timestamp = time.time()
        
        counter = int(timestamp) // totp_secret.period
        
        return self._hotp(
            totp_secret.secret,
            counter,
            totp_secret.digits,
            totp_secret.algorithm,
        )
    
    def _cleanup_used_codes(self, current_time: float, max_age: float) -> None:
        """Remove expired entries from the used codes cache."""
        if current_time - self._last_cleanup < self._used_codes_cleanup_interval:
            return
        
        expired_keys = [
            key for key, ts in self._used_codes.items()
            if current_time - ts > max_age
        ]
        for key in expired_keys:
            del self._used_codes[key]
        
        self._last_cleanup = current_time
    
    def validate_totp(self, totp_secret: TOTPSecret, code: str,
                      user_id: str, window: int = 1,
                      timestamp: float | None = None) -> bool:
        """
        Validate a TOTP code with strong security measures.
        
        Security measures implemented:
        1. Constant-time comparison to prevent timing attacks
        2. Replay attack prevention (each code can only be used once)
        3. Strict input validation
        4. Limited time window (max 1 step in each direction)
        5. Code format validation
        
        Args:
            totp_secret: The TOTPSecret object
            code: The code to validate
            user_id: Unique identifier for the user (for replay prevention)
            window: Number of time steps to check before/after current
                    (max MAX_ALLOWED_WINDOW to prevent weak validation)
            timestamp: Unix timestamp (defaults to current time)
        
        Returns:
            True if the code is valid, False otherwise
        """
        if timestamp is None:
            timestamp = time.time()
        
        # === Input Validation ===
        
        # Enforce maximum window size to prevent weak validation
        if window > self.MAX_ALLOWED_WINDOW:
            raise ValueError(
                f"Window size {window} exceeds maximum allowed value of "
                f"{self.MAX_ALLOWED_WINDOW}. Larger windows weaken security."
            )
        
        if window < 0:
            raise ValueError("Window must be non-negative")
        
        # Validate code format strictly
        if not isinstance(code, str):
            return False
        
        # Code must be exactly the right number of digits
        if len(code) != totp_secret.digits:
            return False
        
        # Code must contain only digits (prevent injection)
        if not re.match(r'^\d+$', code):
            return False
        
        # Validate user_id
        if not user_id or not isinstance(user_id, str):
            raise ValueError("user_id must be a non-empty string")
        
        # === Replay Attack Prevention ===
        
        # Clean up old entries periodically
        max_code_age = totp_secret.period * (2 * self.MAX_ALLOWED_WINDOW + 2)
        self._cleanup_used_codes(timestamp, max_code_age)
        
        # Check if this code was already used by this user
        replay_key = (user_id, code)
        if replay_key in self._used_codes:
            # Code was already used - reject to prevent replay
            return False
        
        # === Time-based Validation ===
        
        current_counter = int(timestamp) // totp_secret.period
        
        valid = False
        matched_counter = None
        
        for offset in range(-window, window + 1):
            counter = current_counter + offset
            expected_code = self._hotp(
                totp_secret.secret,
                counter,
                totp_secret.digits,
                totp_secret.algorithm,
            )
            
            # Use constant-time comparison to prevent timing attacks
            if hmac.compare_digest(code.encode('utf-8'),
                                   expected_code.encode('utf-8')):
                valid = True
                matched_counter = counter
                break
        
        if valid and matched_counter is not None:
            # Record this code as used to prevent replay
            self._used_codes[replay_key] = timestamp
        
        return valid
    
    def generate_qr_code(self, totp_secret: TOTPSecret,
                         output_path: str | None = None) -> bytes | None:
        """
        Generate a QR code image for the TOTP secret.
        
        Args:
            totp_secret: The TOTPSecret object
            output_path: Optional file path to save the QR code image.
                        If None, returns the PNG bytes.
        
        Returns:
            PNG image bytes if output_path is None, otherwise None
        """
        if not HAS_QRCODE:
            raise ImportError(
                "qrcode library is required for QR code generation. "
                "Install it with: pip install qrcode[pil]"
            )
        
        uri = totp_secret.get_otpauth_uri()
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        if output_path:
            img.save(output_path)
            return None
        else:
            buffer = io.BytesIO()
            img.save(buffer, format="PNG")
            return buffer.getvalue()
    
    def generate_qr_code_ascii(self, totp_secret: TOTPSecret) -> str:
        """
        Generate an ASCII representation of the QR code (no dependencies needed).
        
        Args:
            totp_secret: The TOTPSecret object
        
        Returns:
            ASCII string representation of the QR code
        """
        if not HAS_QRCODE:
            raise ImportError(
                "qrcode library is required. Install with: pip install qrcode"
            )
        
        uri = totp_secret.get_otpauth_uri()
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=1,
            border=1,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        # Generate ASCII art
        lines = []
        for row in qr.modules:
            line = ""
            for cell in row:
                line += "██" if cell else "  "
            lines.append(line)
        
        return "\n".join(lines)


class UserMFAManager:
    """
    Manages MFA enrollment and verification for users.
    
    In production, secrets should be stored encrypted in a database.
    This implementation uses an in-memory store for demonstration.
    """
    
    def __init__(self, issuer: str = "MyApp"):
        self.issuer = issuer
        self.totp_generator = TOTPGenerator()
        # In production: use encrypted database storage
        self._user_secrets: dict[str, dict] = {}
        self._user_verified: dict[str, bool] = {}
        # Rate limiting: track failed attempts
        self._failed_attempts: dict[str, list[float]] = {}
        self._max_failed_attempts = 5
        self._lockout_duration = 300  # 5 minutes
    
    def _check_rate_limit(self, user_id: str) -> bool:
        """
        Check if the user is rate-limited due to too many failed attempts.
        
        Returns:
            True if the user is allowed to attempt, False if rate-limited
        """
        if user_id not in self._failed_attempts:
            return True
        
        current_time = time.time()
        # Remove old attempts outside the lockout window
        self._failed_attempts[user_id] = [
            t for t in self._failed_attempts[user_id]
            if current_time - t < self._lockout_duration
        ]
        
        return len(self._failed_attempts[user_id]) < self._max_failed_attempts
    
    def _record_failed_attempt(self, user_id: str) -> None:
        """Record a failed validation attempt for rate limiting."""
        if user_id not in self._failed_attempts:
            self._failed_attempts[user_id] = []
        self._failed_attempts[user_id].append(time.time())
    
    def _clear_failed_attempts(self, user_id: str) -> None:
        """Clear failed attempts after successful validation."""
        self._failed_attempts.pop(user_id, None)
    
    def enroll_user(self, user_id: str, account_name: str,
                    algorithm: str = "SHA1") -> TOTPSecret:
        """
        Start MFA enrollment for a user. Generates a new secret.
        
        The enrollment is not complete until verify_enrollment() is called
        with a valid code from the user's authenticator app.
        
        Args:
            user_id: Unique user identifier
            account_name: User's display name or email
            algorithm: Hash algorithm to use
        
        Returns:
            TOTPSecret for QR code generation
        """
        if not user_id or not isinstance(user_id, str):
            raise ValueError("user_id must be a non-empty string")
        
        totp_secret = self.totp_generator.generate_secret(
            issuer=self.issuer,
            account_name=account_name,
            secret_length=32,  # 256 bits
            algorithm=algorithm,
        )
        
        # Store the secret (not yet verified)
        self._user_secrets[user_id] = totp_secret.to_dict()
        self._user_verified[user_id] = False
        
        return totp_secret
    
    def verify_enrollment(self, user_id: str, code: str) -> bool:
        """
        Complete MFA enrollment by verifying the user can generate valid codes.
        
        This ensures the user has properly set up their authenticator app
        before we consider MFA active for their account.
        
        Args:
            user_id: Unique user identifier
            code: TOTP code from the user's authenticator app
        
        Returns:
            True if enrollment is verified successfully
        """
        if user_id not in self._user_secrets:
            raise ValueError(f"No enrollment found for user {user_id}")
        
        if self._user_verified.get(user_id, False):
            raise ValueError(f"User {user_id} is already enrolled")
        
        totp_secret = TOTPSecret.from_dict(self._user_secrets[user_id])
        
        # Use window=0 for enrollment verification (must be exact)
        # This ensures the user's clock is reasonably synchronized
        is_valid = self.totp_generator.validate_totp(
            totp_secret, code, user_id, window=0
        )
        
        if is_valid:
            self._user_verified[user_id] = True
            return True
        
        return False
    
    def validate_code(self, user_id: str, code: str) -> bool:
        """
        Validate a TOTP code for an enrolled user.
        
        Includes rate limiting to prevent brute force attacks.
        
        Args:
            user_id: Unique user identifier
            code: TOTP code to validate
        
        Returns:
            True if the code is valid
        
        Raises:
            ValueError: If user is not enrolled or rate-limited
        """
        if user_id not in self._user_secrets:
            raise ValueError(f"No MFA enrollment found for user {user_id}")
        
        if not self._user_verified.get(user_id, False):
            raise ValueError(f"MFA enrollment not verified for user {user_id}")
        
        # Check rate limiting
        if not self._check_rate_limit(user_id):
            remaining = self._lockout_duration
            if self._failed_attempts.get(user_id):
                oldest = min(self._failed_attempts[user_id])
                remaining = max(0, self._lockout_duration - (time.time() - oldest))
            raise ValueError(
                f"Too many failed attempts. Try again in {int(remaining)} seconds."
            )
        
        totp_secret = TOTPSecret.from_dict(self._user_secrets[user_id])
        
        is_valid = self.totp_generator.validate_totp(
            totp_secret, code, user_id, window=1
        )
        
        if is_valid:
            self._clear_failed_attempts(user_id)
        else:
            self._record_failed_attempt(user_id)
        
        return is_valid
    
    def remove_user(self, user_id: str) -> bool:
        """
        Remove MFA enrollment for a user.
        
        Args:
            user_id: Unique user identifier
        
        Returns:
            True if the user was removed
        """
        removed = user_id in self._user_secrets
        self._user_secrets.pop(user_id, None)
        self._user_verified.pop(user_id, None)
        self._failed_attempts.pop(user_id, None)
        return removed
    
    def is_enrolled(self, user_id: str) -> bool:
        """Check if a user has completed MFA enrollment."""
        return self._user_verified.get(user_id, False)
    
    def get_enrollment_status(self, user_id: str) -> dict:
        """Get the MFA enrollment status for a user."""
        has_secret = user_id in self._user_secrets
        is_verified = self._user_verified.get(user_id, False)
        is_rate_limited = not self._check_rate_limit(user_id)
        
        failed_count = len(self._failed_attempts.get(user_id, []))
        
        return {
            "user_id": user_id,
            "has_secret": has_secret,
            "is_verified": is_verified,
            "is_rate_limited": is_rate_limited,
            "recent_failed_attempts": failed_count,
        }


def demo():
    """Demonstrate the TOTP MFA system."""
    print("=" * 60)
    print("TOTP Two-Factor Authentication Demo")
    print("=" * 60)
    
    # Initialize the MFA manager
    mfa = UserMFAManager(issuer="DemoApp")
    totp_gen = mfa.totp_generator
    
    # Step 1: Enroll a user
    print("\n--- Step 1: User Enrollment ---")
    user_id = "user_12345"
    account_name = "alice@example.com"
    
    totp_secret = mfa.enroll_user(user_id, account_name)
    
    print(f"User: {account_name}")
    print(f"Secret (base32): {totp_secret.base32_secret}")
    print(f"OTPAuth URI: {totp_secret.get_otpauth_uri()}")
    print(f"Algorithm: {totp_secret.algorithm}")
    print(f"Digits: {totp_secret.digits}")
    print(f"Period: {totp_secret.period}s")
    
    # Generate QR code if available
    if HAS_QRCODE:
        try:
            qr_ascii = totp_gen.generate_qr_code_ascii(totp_secret)
            print(f"\nQR Code (scan with authenticator app):\n{qr_ascii}")
        except Exception as e:
            print(f"\nCould not generate QR code: {e}")
    else:
        print("\nInstall 'qrcode' package for QR code generation:")
        print("  pip install qrcode[pil]")
    
    # Step 2: Generate current TOTP code (simulating authenticator app)
    print("\n--- Step 2: Code Generation ---")
    current_code = totp_gen.generate_totp(totp_secret)
    current_time = time.time()
    time_remaining = totp_secret.period - (int(current_time) % totp_secret.period)
    
    print(f"Current TOTP code: {current_code}")
    print(f"Time remaining: {time_remaining}s")
    print(f"Current timestamp: {int(current_time)}")
    
    # Step 3: Verify enrollment
    print("\n--- Step 3: Verify Enrollment ---")
    enrollment_code = totp_gen.generate_totp(totp_secret)
    success = mfa.verify_enrollment(user_id, enrollment_code)
    print(f"Enrollment verification: {'SUCCESS' if success else 'FAILED'}")
    
    # Step 4: Validate codes
    print("\n--- Step 4: Code Validation ---")
    
    # Valid code
    fresh_code = totp_gen.generate_totp(totp_secret)
    # Note: We need a fresh code since the enrollment code was already used (replay prevention)
    # Generate code for next time step to avoid replay detection
    next_step_time = current_time + totp_secret.period
    next_code = totp_gen.generate_totp(totp_secret, timestamp=next_step_time)
    
    # Validate with matching timestamp
    is_valid = totp_gen.validate_totp(
        totp_secret, next_code, user_id, window=1, timestamp=next_step_time
    )
    print(f"Valid code '{next_code}': {is_valid}")
    
    # Invalid code
    is_valid = mfa.validate_code(user_id, "000000")
    print(f"Invalid code '000000': {is_valid}")
    
    # Wrong length code
    is_valid = totp_gen.validate_totp(totp_secret, "12345", user_id)
    print(f"Wrong length '12345': {is_valid}")
    
    # Non-numeric code
    is_valid = totp_gen.validate_totp(totp_secret, "abcdef", user_id)
    print(f"Non-numeric 'abcdef': {is_valid}")
    
    # Step 5: Security demonstrations
    print("\n--- Step 5: Security Features ---")
    
    # Demonstrate window restriction
    print("\nWindow size restriction:")
    try:
        totp_gen.validate_totp(totp_secret, "123456", user_id, window=5)
        print("  ERROR: Should have rejected large window")
    except ValueError as e:
        print(f"  Correctly rejected: {e}")
    
    # Demonstrate replay prevention
    print("\nReplay attack prevention:")
    test_time = time.time() + 200
    code_for_replay = totp_gen.generate_totp(totp_secret, timestamp=test_time)
    result1 = totp_gen.validate_totp(
        totp_secret, code_for_replay, user_id, timestamp=test_time
    )
    result2 = totp_gen.validate_totp(
        totp_secret, code_for_replay, user_id, timestamp=test_time
    )
    print(f"  First use of code: {result1}")
    print(f"  Replay of same code: {result2} (blocked!)")
    
    # Demonstrate rate limiting
    print("\nRate limiting:")
    for i in range(6):
        try:
            result = mfa.validate_code(user_id, "999999")
            print(f"  Attempt {i + 1}: {'valid' if result else 'invalid'}")
        except ValueError as e:
            print(f"  Attempt {i + 1}: BLOCKED - {e}")
    
    # Step 6: Enrollment status
    print("\n--- Step 6: Enrollment Status ---")
    status = mfa.get_enrollment_status(user_id)
    print(json.dumps(status, indent=2))
    
    # Step 7: Serialization
    print("\n--- Step 7: Secret Serialization ---")
    secret_dict = totp_secret.to_dict()
    print(f"Serialized: {json.dumps(secret_dict, indent=2)}")
    
    restored = TOTPSecret.from_dict(secret_dict)
    restored_code = totp_gen.generate_totp(restored)
    original_code = totp_gen.generate_totp(totp_secret)
    print(f"Original code:  {original_code}")
    print(f"Restored code:  {restored_code}")
    print(f"Match: {original_code == restored_code}")
    
    print("\n" + "=" * 60)
    print("Demo complete!")
    print("=" * 60)


